189→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
190→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
191→  if (!response.ok || !response.body) {
192→    throw new Error(`Failed to open SSE stream (${response.status})`);
193→  }
194→
195→  const reader = response.body.getReader();
196→  const decoder = new TextDecoder();
197→  const events: T[] = [];
198→  let buffer = "";
199→
200→  const timeout = setTimeout(() => {
201→    void reader.cancel();
202→  }, timeoutMs);
203→
204→  try {
205→    while (true) {
206→      const { value, done } = await reader.read();
207→      if (done) {
208→        break;
209→      }
210→
211→      buffer += decoder.decode(value, { stream: true });
212→      const segments = buffer.split("\n\n");
213→      buffer = segments.pop() ?? "";
214→
215→      for (const segment of segments) {
216→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
217→        if (!dataLine) {
218→          continue;
219→        }
220→
221→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
222→        events.push(event);
223→
224→        if (event.type === "error") {
225→          const errorText = (event as { error?: string }).error;
226→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
227→        }
228→
229→        if (event.type === "done") {
230→          return events;
231→        }
232→      }
233→    }
234→  } finally {
235→    clearTimeout(timeout);
236→    reader.releaseLock();
237→  }
238→
239→  return events;
240→}
