242→export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
243→  const response = await fetch(url, init);
244→  if (!response.ok) {
245→    const body = await response.text();
246→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
247→  }
248→
249→  return (await response.json()) as T;
250→}
